#include<bits/stdc++.h>
using namespace std;
const int N=500010,M=500010;
struct edge
{
    int to,flow,nxt;
}e[M*2];
int tot=1,d[N],head[N],now[N],s,t;
void add1(int u,int v,int w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(int u,int v,int w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    memset(d,0,sizeof(d));
    d[s]=1;
    queue<int> q;
    q.push(s);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,flow=e[i].flow;
            if(flow&&!d[v])
            {
                d[v]=d[t]+1;
                if(v==(::t))
                {
                    return true;
                }
                q.push(v);
            }
        }
    }
    return false;
}
int dfs(int x,int flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    int sum=0;
    for(int i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        int v=e[i].to,val=e[i].flow;
        if(val&&d[v]==d[x]+1)
        {
            int tmp=min(flow,dfs(v,val));
            e[i].flow-=tmp;
            e[i^1].flow+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
int dinic()
{
    int ans=0;
    while(bfs())
    {
        memcpy(now,head,sizeof(now));
        ans+=dfs(s,2e9);
    }
    return ans;
}
int main()
{
    int a,b,m;
    scanf("%d%d%d",&a,&b,&m);
    s=a+b+1;
    t=a+b+2;
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        add(u,v+a,1);
    }
    for(int i=1;i<=a;i++)
    {
        add(s,i,1);
    }
    for(int i=1;i<=b;i++)
    {
        add(i+a,t,1);
    }
    printf("%d",dinic());
    return 0;
}
